+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import { getEntityWorld } from '../entity/entity';
+
+export const $aspect = Symbol('aspect');
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Record<string, unknown>;
+    readonly [$aspect]: true;
+} & ((params?: AspectValue<T>) => [Aspect<T>, AspectValue<T>]);
+
+export type AspectValue<T extends readonly Trait[] = readonly Trait[]> = Partial<
+    UnionToIntersection<T[number] extends Trait ? TraitRecord<T[number]> : never>
+>;
+
+type UnionToIntersection<U> = (U extends unknown ? (value: U) => void : never) extends (
+    value: infer I
+) => void
+    ? I
+    : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: T
+): Aspect<FlattenAspects<T>> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isRelation(input)) throw new Error('Relations cannot be constituents of an aspect.');
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const schema: Record<string, unknown> = {};
+    const fields = new Set<string>();
+    for (const trait of traits) {
+        if (trait[$internal].relation) throw new Error('Relations cannot be constituents of an aspect.');
+        const traitSchema = trait.schema;
+        // AoS schemas do not expose their fields until instantiated. They remain valid
+        // constituents and are represented by their record at runtime.
+        if (typeof traitSchema !== 'function') {
+            for (const key of Object.keys(traitSchema)) {
+                if (fields.has(key)) throw new Error(`Aspect constituents overlap on field "${key}".`);
+                fields.add(key);
+                schema[key] = traitSchema[key];
+            }
+        }
+    }
+
+    const id = aspectId++;
+    const aspect = Object.assign((params?: AspectValue<any>) => [aspect, params ?? {}] as const, {
+        [$aspect]: true as const,
+    }) as Aspect<FlattenAspects<T>>;
+    Object.defineProperties(aspect, {
+        id: { value: id, enumerable: true },
+        traits: { value: Object.freeze(traits), enumerable: true },
+        schema: { value: Object.freeze(schema), enumerable: true },
+    });
+    return aspect;
+}
+
+type FlattenOne<T> = T extends Aspect<infer Traits> ? Traits[number] : T;
+type FlattenAspects<T extends readonly unknown[]> = {
+    [K in keyof T]: FlattenOne<T[K]>;
+} extends infer Values
+    ? Values extends readonly Trait[]
+        ? Values
+        : readonly Trait[]
+    : readonly Trait[];
+
+export function hasAspect(entity: Entity, aspect: Aspect) {
+    const world = getEntityWorld(entity);
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(entity: Entity, aspect: Aspect): Record<string, unknown> | undefined {
+    if (!hasAspect(entity, aspect)) return undefined;
+    const world = getEntityWorld(entity);
+    const value: Record<string, unknown> = {};
+    for (const trait of aspect.traits) Object.assign(value, getTrait(world, entity, trait));
+    return value;
+}
+
+export function setAspect(entity: Entity, aspect: Aspect, value: any, triggerChanged = true) {
+    const world = getEntityWorld(entity);
+    const resolved = value instanceof Function ? value(getAspect(entity, aspect)) : value;
+    for (const trait of aspect.traits) {
+        const fields = fieldsForTrait(trait, resolved);
+        if (Object.keys(fields).length) setTrait(world, entity, trait, fields, triggerChanged);
+    }
+}
+
+export function addAspect(entity: Entity, aspect: Aspect, value: any = {}) {
+    const world = getEntityWorld(entity);
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, fieldsForTrait(trait, value)] as ConfigurableTrait);
+    }
+}
+
+export function removeAspect(entity: Entity, aspect: Aspect) {
+    removeTrait(getEntityWorld(entity), entity, ...aspect.traits);
+}
+
+export function fieldsForTrait(trait: Trait, value: Record<string, any> = {}) {
+    if (typeof trait.schema === 'function') return value;
+    const fields: Record<string, any> = {};
+    for (const key of Object.keys(trait.schema)) if (key in value) fields[key] = value[key];
+    return fields;
+}
